#define MAX_ARGS 10
#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000

typedef struct {
    char entry[REC_LENGTH];
    float dist;
} neighbor_t;

kernel void compute_distances(
    const char *sandbox,
    float *z,
    float target_lat,
    float target_long,
    int rec_count)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    const char *rec_iter = sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);

    // Parse latitude and longitude from the record string
    // The original code uses atof on specific offsets
    char lat_str[10];
    char lon_str[10];

    // Extract 5 characters for latitude (based on atof(rec_iter) where rec_iter points to LATITUDE_POS-1)
    // Original: rec_iter = sandbox+(i * REC_LENGTH + LATITUDE_POS - 1); tmp_lat = atof(rec_iter);
    // Original: tmp_long = atof(rec_iter+5);
    // We assume the format is fixed width based on the generator code "%5.1f"
    int idx = i * REC_LENGTH + LATITUDE_POS - 1;

    // Manual parsing to avoid atof in kernel (or use a simple implementation)
    // Since OpenCL doesn't have atof, we implement a simple float parser for the expected format
    // Format expected: " XX.X" or similar (5 chars)

    float tmp_lat = 0.0f;
    float tmp_long = 0.0f;

    // Parse latitude
    int pos = idx;
    float sign = 1.0f;
    if (sandbox[pos] == '-') { sign = -1.0f; pos++; }
    else if (sandbox[pos] == '+') { pos++; }

    float val = 0.0f;
    float frac = 0.0f;
    float divisor = 1.0f;
    int digit_seen = 0;

    // Integer part
    while (pos < idx + 6 && sandbox[pos] >= '0' && sandbox[pos] <= '9') {
        val = val * 10.0f + (sandbox[pos] - '0');
        pos++;
        digit_seen = 1;
    }

    // Decimal point
    if (pos < idx + 6 && sandbox[pos] == '.') {
        pos++;
        while (pos < idx + 6 && sandbox[pos] >= '0' && sandbox[pos] <= '9') {
            frac = frac * 10.0f + (sandbox[pos] - '0');
            divisor *= 10.0f;
            pos++;
        }
    }

    tmp_lat = sign * (val + frac / divisor);

    // Parse longitude (offset +5 from latitude start)
    pos = idx + 5;
    sign = 1.0f;
    if (sandbox[pos] == '-') { sign = -1.0f; pos++; }
    else if (sandbox[pos] == '+') { pos++; }

    val = 0.0f;
    frac = 0.0f;
    divisor = 1.0f;

    while (pos < idx + 11 && sandbox[pos] >= '0' && sandbox[pos] <= '9') {
        val = val * 10.0f + (sandbox[pos] - '0');
        pos++;
    }

    if (pos < idx + 11 && sandbox[pos] == '.') {
        pos++;
        while (pos < idx + 11 && sandbox[pos] >= '0' && sandbox[pos] <= '9') {
            frac = frac * 10.0f + (sandbox[pos] - '0');
            divisor *= 10.0f;
            pos++;
        }
    }

    tmp_long = sign * (val + frac / divisor);

    float diff_lat = tmp_lat - target_lat;
    float diff_long = tmp_long - target_long;

    z[i] = sqrt(diff_lat * diff_lat + diff_long * diff_long);
}

kernel void update_neighbors(
    const char *sandbox,
    const float *z,
    neighbor_t *neighbors,
    int rec_count,
    int k)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    // Find max distance in current neighbors
    float max_dist = -1.0f;
    int max_idx = 0;

    for (int j = 0; j < k; j++) {
        if (neighbors[j].dist > max_dist) {
            max_dist = neighbors[j].dist;
            max_idx = j;
        }
    }

    if (z[i] < neighbors[max_idx].dist) {
        // Copy record string
        for (int c = 0; c < REC_LENGTH - 1; c++) {
            neighbors[max_idx].entry[c] = sandbox[i * REC_LENGTH + c];
        }
        neighbors[max_idx].entry[REC_LENGTH - 1] = '\0';
        neighbors[max_idx].dist = z[i];
    }
}
